diff --git a/vi.c b/vi.c
index eecf2335..3e541769 100644
--- a/vi.c
+++ b/vi.c
@@ -111,6 +111,147 @@ static int vi_nextcol(char *ln, int dir, int *off)
 	return 0;
 }
 
+/* the last rendered column of the given line, measured out of band */
+static int vi_lncmax(char *s)
+{
+	int cmax;
+	ren_state *r;
+	if (!s)
+		return 0;
+	preserve(ren_state*, rstate, rstate = rstates+2;)
+	r = ren_position(s);
+	cmax = MAX(0, r->cmax);
+	if (r->cmax >= 0 && *r->chrs[r->col[r->cmax]] == '\n')
+		cmax = MAX(0, cmax - 1);
+	restore(rstate)
+	return cmax;
+}
+
+/* the number of terminal rows the given line occupies */
+int vi_lnrows(char *s)
+{
+	if (!xlw || !s)
+		return 1;
+	return vi_lncmax(s) / ren_wrapw(vi_lncol) + 1;
+}
+
+/* the terminal row at which the given line starts */
+int vi_srow(int row)
+{
+	int i, trow = -xtopsub;
+	if (!xlw)
+		return row - xtop;
+	for (i = row; i < xtop; i++)
+		trow -= vi_lnrows(lbuf_get(xb, i));
+	for (i = xtop; i < row; i++)
+		trow += vi_lnrows(lbuf_get(xb, i));
+	return trow;
+}
+
+/* the last line visible on the screen, even if only partially */
+static int vi_botrow(void)
+{
+	int row = xtop, trow = -xtopsub, len = lbuf_len(xb);
+	if (!xlw)
+		return MIN(xtop + xrows, MAX(1, len)) - 1;
+	while (row + 1 < len && trow + vi_lnrows(lbuf_get(xb, row)) < xrows)
+		trow += vi_lnrows(lbuf_get(xb, row++));
+	return row;
+}
+
+/* the first line shown in full; the top line may be cut in half */
+#define vi_fullrow()	(xtop + (xtopsub > 0))
+
+/* the last line shown in full; the bottom line may be cut in half */
+static int vi_lastrow(void)
+{
+	int row = vi_botrow();
+	if (xlw && row > xtop && vi_srow(row) + vi_lnrows(lbuf_get(xb, row)) > xrows)
+		row--;
+	return row;
+}
+
+/* advance the top of the screen by n terminal rows; return rows advanced */
+static int vi_topadv(int n)
+{
+	int i = 0, h;
+	if (!xlw) {
+		h = MAX(0, MIN(lbuf_len(xb) - 1, xtop + n));
+		i = h - xtop;
+		xtop = h;
+		return i < 0 ? -i : i;
+	}
+	for (; i < n; i++) {
+		h = vi_lnrows(lbuf_get(xb, xtop));
+		if (xtopsub + 1 < h)
+			xtopsub++;
+		else if (xtop + 1 < lbuf_len(xb))
+			xtop++, xtopsub = 0;
+		else
+			break;
+	}
+	for (; i < -n; i++) {
+		if (xtopsub > 0)
+			xtopsub--;
+		else if (xtop > 0)
+			xtopsub = vi_lnrows(lbuf_get(xb, --xtop)) - 1;
+		else
+			break;
+	}
+	return i;
+}
